	}
	if got.Data.ID != "ch-001" {
		t.Fatalf("expected id=ch-001, got %s", got.Data.ID)
	}
	if got.Data.Name != "ops-alerts" {
		t.Fatalf("expected name=ops-alerts, got %s", got.Data.Name)
